void
print_token(const antlr4::Token* token,
            antlr4::CommonTokenStream& tokens,
            std::ofstream& outFile,
            const antlr4::Lexer& lexer,
            std::string& currentFile,
            int& currentLineOffset)
{
  auto& vocabulary = lexer.getVocabulary();

  auto tokenTypeName =
    std::string(vocabulary.getSymbolicName(token->getType()));

  if (tokenTypeName.empty())
    tokenTypeName = "<UNKNOWN>"; // 处理可能的空字符串情况

  if (tokenTypeMapping.find(tokenTypeName) != tokenTypeMapping.end()) {
    tokenTypeName = tokenTypeMapping[tokenTypeName];
  }

  // Get location information
  int line = token->getLine();
  int col = token->getCharPositionInLine() + 1;

  // Special handling for EOF token
  if (token->getType() == antlr4::Token::EOF) {
    // EOF should be at the last line, column after the last token
    // Find the last non-EOF token
    auto allTokens = tokens.getTokens();
    for (int i = allTokens.size() - 2; i >= 0; i--) {
      auto prevToken = allTokens[i];
      if (prevToken->getType() != antlr4::Token::EOF && 
          prevToken->getChannel() != antlr4::Token::HIDDEN_CHANNEL) {
        line = prevToken->getLine();
        col = prevToken->getCharPositionInLine() + prevToken->getText().length() + 1;
        break;
      }
    }
  }

  std::string locInfo = " Loc=<" + currentFile + ":" + std::to_string(line) + ":" +
                        std::to_string(col) + ">";

  bool startOfLine = false;
  bool leadingSpace = false;

  // Check if token is at start of line (but not EOF)
  if (token->getType() != antlr4::Token::EOF && col == 1) {
    startOfLine = true;
  }

  // Check if token has leading space using hidden tokens
  auto tokenIndex = token->getTokenIndex();
  if (tokenIndex > 0 && token->getType() != antlr4::Token::EOF) {
    auto hiddenTokensToLeft = tokens.getHiddenTokensToLeft(tokenIndex);
    if (!hiddenTokensToLeft.empty()) {
      auto lastHidden = hiddenTokensToLeft.back();
      // Check if the last hidden token is whitespace (not newline)
      if (lastHidden->getChannel() == antlr4::Token::HIDDEN_CHANNEL) {
        auto hiddenText = lastHidden->getText();
        // Check if it contains whitespace (not just newlines)
        if (hiddenText.find(' ') != std::string::npos || 
            hiddenText.find('\t') != std::string::npos) {
          leadingSpace = true;
        }
      }
    }
  }

  if (token->getText() != "<EOF>")
    outFile << tokenTypeName << " '" << token->getText() << "'";
  else
    outFile << tokenTypeName << " '"
            << "'";
  if (startOfLine)
    outFile << "\t [StartOfLine]";
  if (leadingSpace)
    outFile << " [LeadingSpace]";
  outFile << locInfo << std::endl;
}

int
main(int argc, char* argv[])
{
  if (argc != 3) {
    std::cout << "Usage: " << argv[0] << " <input> <output>\n";
    return -1;
  }

  std::ifstream inFile(argv[1]);
  if (!inFile) {
    std::cout << "Error: unable to open input file: " << argv[1] << '\n';
    return -2;
  }

  std::ofstream outFile(argv[2]);
  if (!outFile) {
    std::cout << "Error: unable to open output file: " << argv[2] << '\n';
    return -3;
  }

  std::cout << "程序 '" << argv[0] << std::endl;
  std::cout << "输入 '" << argv[1] << std::endl;
  std::cout << "输出 '" << argv[2] << std::endl;

  // Read input file and preprocess to handle line markers
  std::vector<std::pair<int, std::string>> lineMap; // Maps preprocessed line to (source line, source file)
  std::stringstream buffer;
  std::string line;
  std::string currentFile = argv[1];
  int currentSourceLine = 1;
  int preprocessedLine = 0;

  while (std::getline(inFile, line)) {
    preprocessedLine++;
    // Check for line marker: # linenum filename flags
    if (line.length() > 0 && line[0] == '#') {
      std::istringstream iss(line);
      std::string marker;
      int linenum;
      std::string filename;
      int flags;

      iss >> marker >> linenum >> filename >> flags;
      if (marker == "#" && !filename.empty() && filename != "<built-in>" && filename != "<command line>") {
        // Remove quotes from filename if present
        if (filename.length() >= 2 && filename[0] == '"' && filename[filename.length()-1] == '"') {
          filename = filename.substr(1, filename.length() - 2);
        }
        currentFile = filename;
        currentSourceLine = linenum;
      }
    }
    lineMap.push_back({currentSourceLine, currentFile});
    buffer << line << '\n';
    currentSourceLine++;
  }

  antlr4::ANTLRInputStream input(buffer.str());
  SYsULexer lexer(&input);

  antlr4::CommonTokenStream tokens(&lexer);
  tokens.fill();

  for (auto&& token : tokens.getTokens()) {
    // Skip tokens on hidden channel (whitespace, newlines, etc.)
    if (token->getChannel() == antlr4::Token::HIDDEN_CHANNEL) {
      continue;
    }
    print_token(token, tokens, outFile, lexer, currentFile, currentLineOffset);
  }
}

