void
print_token(const antlr4::Token* token,
            antlr4::CommonTokenStream& tokens,
            std::ofstream& outFile,
            const antlr4::Lexer& lexer,
            const std::vector<std::pair<int, std::string>>& lineMap,
            const std::string& defaultFile)
{
  auto& vocabulary = lexer.getVocabulary();

  auto tokenTypeName =
    std::string(vocabulary.getSymbolicName(token->getType()));

  if (tokenTypeName.empty())
    tokenTypeName = "<UNKNOWN>"; // 处理可能的空字符串情况

  if (tokenTypeMapping.find(tokenTypeName) != tokenTypeMapping.end()) {
    tokenTypeName = tokenTypeMapping[tokenTypeName];
  }

  // Get location information
  int line = token->getLine();
  int col = token->getCharPositionInLine() + 1;

  // Map preprocessed line to source line and file
  std::string currentFile = defaultFile;
  int sourceLine = line;
  if (line > 0 && line <= lineMap.size()) {
    // Find the next valid line mapping (skip line markers)
    for (int i = line - 1; i < lineMap.size(); i++) {
      if (lineMap[i].first != -1) {
        sourceLine = lineMap[i].first;
        currentFile = lineMap[i].second;
        break;
      }
    }
  }

  // Special handling for EOF token
  if (token->getType() == antlr4::Token::EOF) {
    // EOF should be at the last line, column after the last token
    // Find the last non-EOF token
    auto allTokens = tokens.getTokens();
    for (int i = allTokens.size() - 2; i >= 0; i--) {
      auto prevToken = allTokens[i];
      if (prevToken->getType() != antlr4::Token::EOF && 
          prevToken->getChannel() != antlr4::Token::HIDDEN_CHANNEL) {
        int prevLine = prevToken->getLine();
        if (prevLine > 0 && prevLine <= lineMap.size()) {
          // Find the next valid line mapping (skip line markers)
          for (int j = prevLine - 1; j < lineMap.size(); j++) {
            if (lineMap[j].first != -1) {
              sourceLine = lineMap[j].first;
              currentFile = lineMap[j].second;
              break;
            }
          }
        }
        col = prevToken->getCharPositionInLine() + prevToken->getText().length() + 1;
        break;
      }
    }
  }

  std::string locInfo = " Loc=<" + currentFile + ":" + std::to_string(sourceLine) + ":" +
                        std::to_string(col) + ">";

  bool startOfLine = false;
  bool leadingSpace = false;

  // Check if token is at start of line (but not EOF)
  // A token is at start of line if it's the first non-whitespace token on that line
  if (token->getType() != antlr4::Token::EOF) {
    auto tokenIndex = token->getTokenIndex();
    if (tokenIndex > 0) {
      auto hiddenTokensToLeft = tokens.getHiddenTokensToLeft(tokenIndex);
      if (hiddenTokensToLeft.empty()) {
        // No hidden tokens to the left, so this is the first token on this line
        startOfLine = true;
      } else {
        // Check if the last hidden token ends with a newline
        auto lastHidden = hiddenTokensToLeft.back();
        auto hiddenText = lastHidden->getText();
        if (!hiddenText.empty() && hiddenText.back() == '\n') {
          startOfLine = true;
        }
      }
    } else {
      // First token in the file
      startOfLine = true;
    }

    // Check if token has leading space using hidden tokens
    if (tokenIndex > 0) {
      auto hiddenTokensToLeft = tokens.getHiddenTokensToLeft(tokenIndex);
      if (!hiddenTokensToLeft.empty()) {
        auto lastHidden = hiddenTokensToLeft.back();
        // Check if the last hidden token is whitespace (not newline)
        if (lastHidden->getChannel() == antlr4::Token::HIDDEN_CHANNEL) {
          auto hiddenText = lastHidden->getText();
          // Check if it contains whitespace (not just newlines)
          if (hiddenText.find(' ') != std::string::npos || 
              hiddenText.find('\t') != std::string::npos) {
            leadingSpace = true;
          }
        }
      }
    }
  }

  if (token->getText() != "<EOF>")
    outFile << tokenTypeName << " '" << token->getText() << "'";
  else
    outFile << tokenTypeName << " '"
            << "'";
  if (startOfLine)
    outFile << "\t [StartOfLine]";
  if (leadingSpace)
    outFile << " [LeadingSpace]";
  outFile << locInfo << std::endl;
}

