Expr*
Ast2Asg::operator()(ast::AssignmentExpressionContext* ctx)
{
  if (auto p = ctx->logicalOrExpression())
    return self(p);

  auto ret = make<BinaryExpr>();

  // Get the assignment operator
  auto opToken = dynamic_cast<antlr4::tree::TerminalNode*>(ctx->assignmentOperator()->children[0])
                   ->getSymbol()
                   ->getType();

  switch (opToken) {
    case ast::Equal:
      ret->op = ret->kAssign;
      break;
    case ast::PlusEqual:
      ret->op = ret->kAdd;
      break;
    case ast::MinusEqual:
      ret->op = ret->kSub;
      break;
    case ast::StarEqual:
      ret->op = ret->kMul;
      break;
    case ast::SlashEqual:
      ret->op = ret->kDiv;
      break;
    case ast::PercentEqual:
      ret->op = ret->kRem;
      break;
    case ast::LessLessEqual:
      ret->op = ret->kShl;
      break;
    case ast::GreaterGreaterEqual:
      ret->op = ret->kShr;
      break;
    case ast::AmpEqual:
      ret->op = ret->kAnd;
      break;
    case ast::PipeEqual:
      ret->op = ret->kOr;
      break;
    case ast::CaretEqual:
      ret->op = ret->kXor;
      break;
    default:
      ABORT();
  }

  ret->lft = self(ctx->unaryExpression());
  ret->rht = self(ctx->assignmentExpression());
  return ret;
}

